embed-borders.general:
.embed-borders .markdown-embed, .embed-borders .internal-embed:not(.image-embed) {
border: 1px solid rgba(var(--ctp-accent), 0.45);
border-left: 4px solid rgb(var(--ctp-accent));
}

media-polished.general:
.media-polished .markdown-preview-view img:not(.emoji) {
border: 1px solid rgba(var(--ctp-accent), 0.2);
padding: 4px;
background: rgba(var(--ctp-mantle), 0.5);
}

media-large-controls.general:
.media-large-controls audio {
height: 72px;
border-radius: 36px;
max-width: 600px;
}

.media-large-controls audio::-webkit-media-controls-play-button {
width: 48px;
height: 48px;
}

.media-large-controls audio::-webkit-media-controls-timeline {
height: 8px;
}

.media-large-controls audio::-webkit-media-controls-current-time-display, .media-large-controls audio::-webkit-media-controls-time-remaining-display {
font-size: 14px;
}

media-waveform.general:
